import{_ as e,c as t,o as r,a4 as a}from"./chunks/framework.HaEZziQ1.js";const g=JSON.parse('{"title":"开源的前端基础练手项目","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端基础练手项目/开源的前端基础练手项目.md","filePath":"Document/前端基础练手项目/开源的前端基础练手项目.md","lastUpdated":1709668918000}'),o={name:"Document/前端基础练手项目/开源的前端基础练手项目.md"},s=a('<h1 id="开源的前端基础练手项目" tabindex="-1">开源的前端基础练手项目 <a class="header-anchor" href="#开源的前端基础练手项目" aria-label="Permalink to &quot;开源的前端基础练手项目&quot;">​</a></h1><p><a href="https://juejin.cn/post/7304932252827287604" target="_blank" rel="noreferrer">2023最全高质量前端资源分享 - 掘金 (juejin.cn)</a></p><p><a href="https://www.smashingmagazine.com/" target="_blank" rel="noreferrer">Smashing Magazine — For Web Designers And Developers</a></p><p><a href="https://roadmap.sh/" target="_blank" rel="noreferrer">Developer Roadmaps - roadmap.sh</a></p><h2 id="前端小技巧、小知识" tabindex="-1">前端小技巧、小知识： <a class="header-anchor" href="#前端小技巧、小知识" aria-label="Permalink to &quot;前端小技巧、小知识：&quot;">​</a></h2><p>CSS battle【在线比拼 CSS】 : <a href="https://cssbattle.dev" target="_blank" rel="noreferrer">https://cssbattle.dev</a> Learn CSS layout【学习 CSS 布局】：<a href="http://learnlayout.com" target="_blank" rel="noreferrer">http://learnlayout.com</a> Flexbox Froggy【学习 Flex 布局的小游戏】：<a href="http://flexboxfroggy.com" target="_blank" rel="noreferrer">http://flexboxfroggy.com</a> EnjoyCSS【在线CSS代码可视化工具】：<a href="https://enjoycss.com" target="_blank" rel="noreferrer">https://enjoycss.com</a> CSS-Tricks 【CSS 技巧】：<a href="https://css-tricks.com" target="_blank" rel="noreferrer">https://css-tricks.com</a> Neumorphism【实现新拟态效果】：<a href="https://neumorphism.io" target="_blank" rel="noreferrer">https://neumorphism.io</a> uiGradients【分享渐变色】：<a href="https://uigradients.com" target="_blank" rel="noreferrer">https://uigradients.com</a> JavaScript【一个一直更新的JavaScript 的语法文档，主要会写如何去避免一些常见的错误】：<a href="https://bonsaiden.github.io/JavaScript-Garden/zh/" target="_blank" rel="noreferrer">https://bonsaiden.github.io/JavaScript-Garden/zh/</a> JS Tips【JS 技巧】：<a href="https://www.jstips.co" target="_blank" rel="noreferrer">https://www.jstips.co</a> JSweekly【技术周刊 】：<a href="https://javascriptweekly.com" target="_blank" rel="noreferrer">https://javascriptweekly.com</a> CDNJS【JavaScript 资料库】：<a href="https://cdnjs.com/libraries" target="_blank" rel="noreferrer">https://cdnjs.com/libraries</a> Beautiful Open 【开源 JS 库集合】：<a href="https://beautifulopen.com" target="_blank" rel="noreferrer">https://beautifulopen.com</a> JavaScript Fun【代码库集合】：<a href="https://www.javascript.fun" target="_blank" rel="noreferrer">https://www.javascript.fun</a> Stack Overflow【编程人员问答网】：<a href="https://stackoverflow.com" target="_blank" rel="noreferrer">https://stackoverflow.com</a> 掘金【高质量技术社区】：<a href="https://juejin.im" target="_blank" rel="noreferrer">https://juejin.im</a> Codrops【网页设计开发博客】：<a href="https://tympanus.net" target="_blank" rel="noreferrer">https://tympanus.net</a> CodePen【一个网站前端设计开发平台，针对网站前端代码的一个工具，上面有各种效果的案例特效（炫技），可以在他们的 demo 基础上开发自己的前端设计。】： <a href="https://codepen.io" target="_blank" rel="noreferrer">https://codepen.io</a> CodeSandBox【提供一个在线开发环境的“沙盒”，主流的框架如 React、Vue、Angular 等，都可即开即用、实时编译预览，非常方便。】： <a href="https://codesandbox.io" target="_blank" rel="noreferrer">https://codesandbox.io</a> JS Bin【轻量级在线编辑器网站】：<a href="https://jsbin.com" target="_blank" rel="noreferrer">https://jsbin.com</a> ICONSVG【在线自定义设计SVG图标素材】：<a href="https://iconsvg.xyz" target="_blank" rel="noreferrer">https://iconsvg.xyz</a> OpenMoji【免费表情符号库】：<a href="https://www.openmoji.org" target="_blank" rel="noreferrer">https://www.openmoji.org</a> Share Icon 【免费矢量素材图库】：<a href="https://www.shareicon.net" target="_blank" rel="noreferrer">https://www.shareicon.net</a> tableconvert 【在线表格编辑器】：<a href="https://tableconvert.com" target="_blank" rel="noreferrer">https://tableconvert.com</a> Feathericons【极简 ICON 图标集】：<a href="https://feathericons.com" target="_blank" rel="noreferrer">https://feathericons.com</a> HTML5UP 【提供大量的HTML5模版】：<a href="https://html5up.net/" target="_blank" rel="noreferrer">https://html5up.net/</a> 趣IT【一个会更新面试题和练习题的宝藏王】<a href="https://www.funit.cn/" target="_blank" rel="noreferrer">https://www.funit.cn/</a></p><p>前端工程师一般都喜欢去哪些网站逛？：<a href="https://www.zhihu.com/question/28478379/answer/2813314123" target="_blank" rel="noreferrer">https://www.zhihu.com/question/28478379/answer/2813314123</a></p><p>免费闯关式编程网站：<a href="https://www.freecodecamp.org/" target="_blank" rel="noreferrer">https://www.freecodecamp.org/</a></p><p>10 个学习 JavaScript 的必逛网站：<a href="https://zhuanlan.zhihu.com/p/483140763" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/483140763</a></p><p>前端开发常用的哪些工具软件：<a href="https://www.zhihu.com/question/64606609/answer/2499762817" target="_blank" rel="noreferrer">https://www.zhihu.com/question/64606609/answer/2499762817</a></p><p>50项目50天：<a href="https://github.com/bradtraversy/50projects50days" target="_blank" rel="noreferrer">https://github.com/bradtraversy/50projects50days</a></p><p>每个开发人员都应该知道的 33 个 JavaScript 概念：<a href="https://github.com/leonardomso/33-js-concepts" target="_blank" rel="noreferrer">https://github.com/leonardomso/33-js-concepts</a></p><p>1000 个 JavaScript 面试问题列表：<a href="https://github.com/sudheerj/javascript-interview-questions" target="_blank" rel="noreferrer">https://github.com/sudheerj/javascript-interview-questions</a></p><p>收集原生JavaScript项目：<a href="https://github.com/Vishal-raj-1/Awesome-JavaScript-Projects" target="_blank" rel="noreferrer">https://github.com/Vishal-raj-1/Awesome-JavaScript-Projects</a></p><p>满足您所有开发需求的简短 JavaScript 代码片段：<a href="https://github.com/30-seconds/30-seconds-of-code" target="_blank" rel="noreferrer">https://github.com/30-seconds/30-seconds-of-code</a></p><p>JavaScript 项目的一组最佳实践：<a href="https://github.com/elsewhencode/project-guidelines" target="_blank" rel="noreferrer">https://github.com/elsewhencode/project-guidelines</a></p><p>30天原生JS挑战赛：<a href="https://github.com/wesbos/JavaScript30" target="_blank" rel="noreferrer">https://github.com/wesbos/JavaScript30</a></p><p>30 天的 JavaScript 编程挑战：<a href="https://github.com/Asabeneh/30-Days-Of-JavaScript" target="_blank" rel="noreferrer">https://github.com/Asabeneh/30-Days-Of-JavaScript</a></p><p>每个 JavaScript 工程师都应懂的33个概念：<a href="https://github.com/stephentian/33-js-concepts" target="_blank" rel="noreferrer">https://github.com/stephentian/33-js-concepts</a></p><p>GitHub 上有什么好玩又有挑战的前端项目？：<a href="https://www.zhihu.com/question/30470886/answer/2722126779" target="_blank" rel="noreferrer">https://www.zhihu.com/question/30470886/answer/2722126779</a></p><h2 id="让自己的前端知识更全面" tabindex="-1">让自己的前端知识更全面 <a class="header-anchor" href="#让自己的前端知识更全面" aria-label="Permalink to &quot;让自己的前端知识更全面&quot;">​</a></h2><p>计算机知识庞大冗杂，尤其前端领域，知识概念，框架原理不断推崇出新。在学习的过程中我们要不断进行总结梳理，形成某一个知识领域的知识图谱。这个知识图谱还可以帮助我们后期进行回顾复习。</p><p>下面是前端前辈进行的总结：</p><ul><li><a href="https://tsejx.github.io/javascript-guidebook/" target="_blank" rel="noreferrer">JavaScript Guidebook - 📚 JavaScript 知识图谱：ECMAScript、DOM、BOM、HTML5、计算机网络 - JavaScript Guidebook (tsejx.github.io)</a>：JavaScript 知识图谱 – ECMAScript | DOM | BOM | HTML5 | 计算机网络 | 设计模式</li><li><a href="https://tsejx.github.io/react-guidebook/" target="_blank" rel="noreferrer">React Guidebook - 📚 React 知识图谱 关于概念、技巧、生态、前沿、源码核心 - React Guidebook (tsejx.github.io)</a>：：React 知识图谱 – 基本概念 | 进阶用法 | 框架生态 | 前沿技术 | 源码核心</li><li><a href="https://tsejx.github.io/webpack-guidebook/" target="_blank" rel="noreferrer">Webpack Guidebook - 📚 Webpack 知识图谱：模块化、基础概念、工作原理、实战应用 - Webpack Guidebook (tsejx.github.io)</a>：：Webpack 知识图谱 – 模块化 | 基础概念 | 工作原理 | 实战应用</li><li><a href="https://tsejx.github.io/devops-guidebook/" target="_blank" rel="noreferrer">DevOps Guidebook - 📚 React 知识图谱 关于概念、技巧、生态、前沿、源码核心 (tsejx.github.io)</a>：：DevOps 知识图谱 – Linux | Nginx | 数据库 | 部署 | DevOps</li><li><a href="https://tsejx.github.io/vue-guidebook/" target="_blank" rel="noreferrer">Vue Guidebook - 📚 Vue 知识图谱 关于用法、响应式原理、编译原理以及生态 - Vue Guidebook (tsejx.github.io)</a>：Vue 知识图谱 – 基本概念 | 响应式原理 | 编译原理 | 框架生态</li><li><a href="https://tsejx.github.io/css-guidebook/" target="_blank" rel="noreferrer">CSS Guidebook - 📚 CSS 知识图谱 新特性、属性、布局、响应式、动画 - CSS Guidebook (tsejx.github.io)</a>：CSS 知识图谱 – 特性 | 属性 | 布局 | 响应式 | 动画</li><li><a href="https://tsejx.github.io/node-guidebook/" target="_blank" rel="noreferrer">Node Guidebook - 📚 Node 知识图谱 关于模块、JS 异步编程、进程、I/O、服务端应用等 - Node Guidebook (tsejx.github.io)</a>：Node.js 知识图谱 – 模块 | 异步编程 | 进程 | I/O | 服务端应用</li><li><a href="https://tsejx.github.io/typescript-guidebook/" target="_blank" rel="noreferrer">TypeScript Guidebook - 📚 TypeScript 知识图谱 构建 JS 语言超集 TS 知识体系 (tsejx.github.io)</a>：TypeScript 知识图谱 – 静态类型检查 | 语法基础 | 配置使用 | 编译原理</li><li><a href="https://tsejx.github.io/cross-platform-guidebook/" target="_blank" rel="noreferrer">Cross Platform Guidebook - 📚 跨平台开发知识体系 - Cross Platform Guidebook (tsejx.github.io)</a>：跨平台开发知识图谱 – HybridApp、ReactNative、小程序、Flutter、Electron</li><li><a href="https://tsejx.github.io/data-structure-and-algorithms-guidebook/" target="_blank" rel="noreferrer">Data Structure and Algorithms Guidebook - 📚 数据结构与算法知识图谱 关于数据结构、算法、手写代码、编程能力提升 - Data Structure and Algorithms Guidebook (tsejx.github.io)</a>：数据结构与算法知识图谱 – 数据结构 | 算法 | 编程实现</li><li><a href="https://tsejx.github.io/visualization-guidebook/" target="_blank" rel="noreferrer">前端图像学 Guidebook - 📚 前端图像学 知识图谱 Canvas、SVG、WebGL - Visualization Guidebook (tsejx.github.io)</a>：前端图像学知识图谱 – Canvas | SVG | WebGL</li><li><a href="https://tsejx.github.io/database-guidebook/" target="_blank" rel="noreferrer">Unicorn! · GitHub (tsejx.github.io)</a>：MySQL、MongoDB</li></ul><p>要想自己的前端知识学的扎实，我们就一定要形成这样一个个知识图谱，里面从基础概念到应用到原理，让自己的知识脉络形成一张网，然后我们不断地在这张网上进行修补或扩充。很多人觉得前端的知识点零碎杂就是因为没有形成这样的知识网，这样也容易导致开发中遇到问题的时候，不知道该往哪个方向去想。</p>',25),i=[s];function n(h,p,l,c,b,u){return r(),t("div",null,i)}const d=e(o,[["render",n]]);export{g as __pageData,d as default};
